SELECT '[default] Preventivo firmato → crea progetto', 'Quando un preventivo viene firmato: notifica Telegram e crea automaticamente il progetto con task AI.', 'paused', 'event', '{"event_type":"preventivo_firmato"}'::jsonb, E'[{"id":"trg","type":"trigger_event","position":{"x":100,"y":200},"data":{"event_type":"preventivo_firmato"}},{"id":"tg","type":"tool_send_telegram","position":{"x":420,"y":200},"data":{"message":"✅ <b>Preventivo firmato!</b>\\nCliente: {{signer_name}}\\nTitolo: {{title}}\\nImporto: €{{total}}"}},{"id":"mkproj","type":"tool_create_project","position":{"x":740,"y":200},"data":{"quote_id":"{{quote_id}}"}}]'::jsonb, '[{"id":"e-trg-tg","source":"trg","target":"tg"},{"id":"e-tg-mkproj","source":"tg","target":"mkproj"}]'::jsonb, '{}'::jsonb
WHERE NOT EXISTS (SELECT 1 FROM workflows WHERE name = '[default] Preventivo firmato → crea progetto');

INSERT INTO workflows (name, description, status, trigger_type, trigger_config, nodes, edges, variables)
SELECT '[default] Weekly digest', 'Ogni lunedì alle 09:00: riassume i KPI della settimana precedente (lead, bookings, pagamenti, revenue) via AI e li invia su Telegram.', 'paused', 'cron', '{"interval_hours":168,"time":"09:00"}'::jsonb, E'[{"id":"trg","type":"trigger_cron","position":{"x":100,"y":200},"data":{"interval_hours":168,"time":"09:00"}},{"id":"q","type":"tool_db_query","position":{"x":420,"y":200},"data":{"query":"SELECT (SELECT COUNT(*) FROM leads WHERE created_at > NOW() - INTERVAL ''7 days'') AS leads_7d, (SELECT COUNT(*) FROM calendar_bookings WHERE created_at > NOW() - INTERVAL ''7 days'') AS bookings_7d, (SELECT COUNT(*) FROM payments WHERE created_at > NOW() - INTERVAL ''7 days'' AND status = ''completed'') AS payments_7d, (SELECT COALESCE(SUM(amount), 0) FROM payments WHERE created_at > NOW() - INTERVAL ''7 days'' AND status = ''completed'') AS revenue_7d, (SELECT COUNT(*) FROM client_projects WHERE created_at > NOW() - INTERVAL ''7 days'') AS new_projects_7d","params":[]}},{"id":"sum","type":"llm_summarize","position":{"x":740,"y":200},"data":{"max_length":100,"style":"telegrafico"}},{"id":"tg","type":"tool_send_telegram","position":{"x":1060,"y":200},"data":{"message":"📈 <b>Weekly digest</b>\\n{{summary}}"}}]'::jsonb, '[{"id":"e-trg-q","source":"trg","target":"q"},{"id":"e-q-sum","source":"q","target":"sum"},{"id":"e-sum-tg","source":"sum","target":"tg"}]'::jsonb, '{}'::jsonb
WHERE NOT EXISTS (SELECT 1 FROM workflows WHERE name = '[default] Weekly digest');
